public enum MdbxFfiError: Swift.Error, Equatable, Hashable, Foundation.LocalizedError {



    case Storage(message: String
    )
    case Serialization(message: String
    )
    case InvalidEntryType(entryType: String
    )
    case LockPoisoned






    public var errorDescription: String? {
        String(reflecting: self)
    }

}

#if compiler(>=6)
extension MdbxFfiError: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeMdbxFfiError: FfiConverterRustBuffer {
    typealias SwiftType = MdbxFfiError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> MdbxFfiError {
        let variant: Int32 = try readInt(&buf)
        switch variant {




        case 1: return .Storage(
            message: try FfiConverterString.read(from: &buf)
            )
        case 2: return .Serialization(
            message: try FfiConverterString.read(from: &buf)
            )
        case 3: return .InvalidEntryType(
            entryType: try FfiConverterString.read(from: &buf)
            )
        case 4: return .LockPoisoned

         default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: MdbxFfiError, into buf: inout [UInt8]) {
        switch value {





        case let .Storage(message):
            writeInt(&buf, Int32(1))
            FfiConverterString.write(message, into: &buf)


        case let .Serialization(message):
            writeInt(&buf, Int32(2))
            FfiConverterString.write(message, into: &buf)


        case let .InvalidEntryType(entryType):
            writeInt(&buf, Int32(3))
            FfiConverterString.write(entryType, into: &buf)


        case .LockPoisoned:
            writeInt(&buf, Int32(4))

        }
    }
}


