private enum InitializationResult {
    case ok
    case contractVersionMismatch
    case apiChecksumMismatch
}
// Use a global variable to perform the versioning checks. Swift ensures that
// the code inside is only computed once.
private let initializationResult: InitializationResult = {
    // Get the bindings contract version from our ComponentInterface
    let bindings_contract_version = 30
    // Get the scaffolding contract version by calling the into the dylib
    let scaffolding_contract_version = ffi_mdbx_ffi_uniffi_contract_version()
    if bindings_contract_version != scaffolding_contract_version {
        return InitializationResult.contractVersionMismatch
    }
    if (uniffi_mdbx_ffi_checksum_func_create_vault() != 52911) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_mdbx_ffi_checksum_func_create_vault_with_tiga_mode() != 23422) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_mdbx_ffi_checksum_func_open_vault() != 57854) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_mdbx_ffi_checksum_func_open_vault_with_security_key() != 15926) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_mdbx_ffi_checksum_method_mdbxvault_create_entry() != 56932) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_mdbx_ffi_checksum_method_mdbxvault_create_project() != 43655) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_mdbx_ffi_checksum_method_mdbxvault_delete_entry() != 40302) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_mdbx_ffi_checksum_method_mdbxvault_info() != 5011) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_mdbx_ffi_checksum_method_mdbxvault_list_deleted_entries() != 56592) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_mdbx_ffi_checksum_method_mdbxvault_list_entries() != 27045) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_mdbx_ffi_checksum_method_mdbxvault_move_entry() != 25556) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_mdbx_ffi_checksum_method_mdbxvault_reset_master_password() != 65069) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_mdbx_ffi_checksum_method_mdbxvault_reset_master_password_with_tiga_mode() != 21525) {
        return InitializationResult.apiChecksumMismatch
